  ('judicial-d35ec6db-moex-00422', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列何者為民法規定財團法人與社團法人之必設機關？', '["董事", "監察人", "代理人", "社員總會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00423', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '民法第248條規定：「訂約當事人之一方，由他方受有定金時，推定其契約成立。」該定金之性 質為：', '["解約定金", "證約定金", "成約定金", "違約定金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00424', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '關於無因管理之類型，下列敘述，何者錯誤？', '["客觀上屬於他人事務，管理人有為他人管理事務之意思，不論管理是否有利於他人，屬適法無 因管理", "客觀上屬於他人事務，管理人主觀上知其所管理者，係他人事務，但無為他人管理事務之意思， 屬不法管理", "客觀上屬於他人事務，管理人主觀上不知其所管理者，係他人事務，且無為他人管理事務之意 思，屬誤信管理", "客觀上屬於自己事務，管理人主觀上誤以為係他人事務而管理，屬幻想管理 20420 20520"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00425', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲男之叔叔為乙，乙之配偶為丙。乙死亡後，甲與丙結婚，其效力如何？', '["有效", "得撤銷", "效力未定", "無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00426', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列何種約定，民法未明定須依書面，始生效力？', '["夫妻冠姓之約定", "夫妻協議一定數額之自由處分金", "父母委託他人行使對其未成年子女監護之職務", "養父母與養子女合意終止收養契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
